modules.fpm_unpack:
`timescale 1ns/1ps
module fpm_unpack(
    input  [31:0] a,
    input  [31:0] b,
    output        a_sign,
    output [7:0]  a_exp,
    output [23:0] a_mant,
    output        b_sign,
    output [7:0]  b_exp,
    output [23:0] b_mant,
    output        a_is_nan,
    output        a_is_inf,
    output        a_is_zero,
    output        b_is_nan,
    output        b_is_inf,
    output        b_is_zero
);
    // Unpack a
    wire a_sign_bit = a[31];
    wire [7:0] a_exp_bits = a[30:23];
    wire [22:0] a_mant_bits = a[22:0];

    // Unpack b
    wire b_sign_bit = b[31];
    wire [7:0] b_exp_bits = b[30:23];
    wire [22:0] b_mant_bits = b[22:0];

    // Detect special cases for a
    wire a_is_zero_int = (a_exp_bits == 8'b0) && (a_mant_bits == 23'b0);
    wire a_is_denormal = (a_exp_bits == 8'b0) && (a_mant_bits != 23'b0);
    wire a_is_inf_int = (a_exp_bits == 8'hFF) && (a_mant_bits == 23'b0);
    wire a_is_nan_int = (a_exp_bits == 8'hFF) && (a_mant_bits != 23'b0);

    // Detect special cases for b
    wire b_is_zero_int = (b_exp_bits == 8'b0) && (b_mant_bits == 23'b0);
    wire b_is_denormal = (b_exp_bits == 8'b0) && (b_mant_bits != 23'b0);
    wire b_is_inf_int = (b_exp_bits == 8'hFF) && (b_mant_bits == 23'b0);
    wire b_is_nan_int = (b_exp_bits == 8'hFF) && (b_mant_bits != 23'b0);

    // Mantissa with implicit 1 for normalized numbers
    wire [23:0] a_mant_int = (a_is_denormal || a_is_zero_int) ? 
                             {1'b0, a_mant_bits} : 
                             {1'b1, a_mant_bits};

    wire [23:0] b_mant_int = (b_is_denormal || b_is_zero_int) ? 
                             {1'b0, b_mant_bits} : 
                             {1'b1, b_mant_bits};

    // Assign outputs for a
    assign a_sign = a_sign_bit;
    assign a_exp = a_exp_bits;
    assign a_mant = a_mant_int;
    assign a_is_zero = a_is_zero_int;
    assign a_is_inf = a_is_inf_int;
    assign a_is_nan = a_is_nan_int;

    // Assign outputs for b
    assign b_sign = b_sign_bit;
    assign b_exp = b_exp_bits;
    assign b_mant = b_mant_int;
    assign b_is_zero = b_is_zero_int;
    assign b_is_inf = b_is_inf_int;
    assign b_is_nan = b_is_nan_int;

endmodule

modules.fpm_multiply:
`timescale 1ns/1ps
module fpm_multiply(
    input         a_sign,
    input  [7:0]  a_exp,
    input  [23:0] a_mant,
    input         b_sign,
    input  [7:0]  b_exp,
    input  [23:0] b_mant,
    output        result_sign,
    output [47:0] product,
    output [9:0]  raw_exp
);
    // Sign is XOR of input signs
    assign result_sign = a_sign ^ b_sign;

    // Product is the 48-bit result of multiplying two 24-bit mantissas
    assign product = a_mant * b_mant;

    // Raw exponent: sum of exponents minus bias (127 for single precision)
    // Result uses 10 bits to accommodate exponent range (0-254 gives 0-381)
    assign raw_exp = a_exp + b_exp - 8'd127;

endmodule

modules.fpm_normalize:
`timescale 1ns/1ps
module fpm_normalize(
    input  [47:0] product,
    input  [9:0]  raw_exp,
    output [22:0] norm_frac,
    output [9:0]  norm_exp,
    output        guard,
    output        sticky
);
    wire [47:0] shifted;
    wire [4:0] shift_amount;
    wire shift_right;

    // Check if we need to shift right (bit 47 is set)
    assign shift_right = product[47];

    // Find position of leading 1 for left shift case
    // If bit46=1, shift_amount=1; if bit45=1, shift_amount=2; etc.
    assign shift_amount = shift_right ? 5'd0 :
                          product[46] ? 5'd1 :
                          product[45] ? 5'd2 :
                          product[44] ? 5'd3 :
                          product[43] ? 5'd4 :
                          product[42] ? 5'd5 :
                          product[41] ? 5'd6 :
                          product[40] ? 5'd7 :
                          5'd0;

    // Shift: right by 1 if bit47=1, else left by shift_amount
    assign shifted = shift_right ? (product >> 1) : (product << shift_amount);

    // Extract 23-bit fraction from bits [46:24]
    assign norm_frac = shifted[46:24];

    // Guard bit is bit 23
    assign guard = shifted[23];

    // Sticky bit is OR of bits [22:0]
    assign sticky = |shifted[22:0];

    // Exponent adjustment: 
    // If shift_right: increment by 1 (we shifted right, so exponent increases)
    // Else: no change (leading 1 is already in implicit position)
    assign norm_exp = shift_right ? (raw_exp + 1) : raw_exp;

endmodule

modules.fpm_round_pack:
`timescale 1ns/1ps
module fpm_round_pack(
    input         sign,
    input  [22:0] norm_frac,
    input  [9:0]  norm_exp,
    input         guard,
    input         sticky,
    output reg [31:0] result,
    output reg        overflow,
    output reg        underflow
);

    always @(*) begin
        reg [23:0] rounded_frac;
        reg [9:0] final_exp;
        reg should_round_up;

        overflow = 0;
        underflow = 0;

        // Determine if we should round up
        // Round to nearest even: round up if guard=1 and (sticky=1 or frac[0]=1)
        should_round_up = guard & (sticky | norm_frac[0]);

        // Apply rounding to fraction
        rounded_frac = {1'b0, norm_frac};
        if (should_round_up) begin
            rounded_frac = rounded_frac + 1;
        end

        // Check if rounding overflowed the fraction (24-bit value becomes 24'h1000000)
        if (rounded_frac[23]) begin
            // Fraction overflowed, increment exponent
            final_exp = norm_exp + 1;
        end else begin
            final_exp = norm_exp;
        end

        // Handle special cases
        if (final_exp == 10'h0) begin
            // Underflow: return signed zero
            underflow = 1;
            result = {sign, 31'h0};
        end else if (final_exp >= 10'hFF) begin
            // Overflow: return signed infinity
            overflow = 1;
            result = {sign, 8'hFF, 23'h0};
        end else begin
            // Normal case: pack into IEEE 754 format
            // Sign (1 bit) | Exponent (8 bits) | Fraction (23 bits)
            result = {sign, final_exp[7:0], rounded_frac[22:0]};
        end
    end

endmodule

modules.fpm_special:
`timescale 1ns/1ps
module fpm_special(
    input         a_is_nan,
    input         a_is_inf,
    input         a_is_zero,
    input         b_is_nan,
    input         b_is_inf,
    input         b_is_zero,
    input         result_sign,
    output        is_special,
    output reg [31:0] special_result
);

    // is_special is 1 if any operand is special (NaN, Inf, or Zero)
    assign is_special = a_is_nan | a_is_inf | a_is_zero | b_is_nan | b_is_inf | b_is_zero;

    always @(*) begin
        if (a_is_nan | b_is_nan) begin
            // NaN × anything → NaN
            special_result = 32'h7FC00000;
        end
        else if ((a_is_inf & b_is_zero) | (a_is_zero & b_is_inf)) begin
            // Inf × 0 or 0 × Inf → NaN
            special_result = 32'h7FC00000;
        end
        else if (a_is_inf | b_is_inf) begin
            // Inf × normal or Inf × Inf → Inf with sign
            special_result = result_sign ? 32'hFF800000 : 32'h7F800000;
        end
        else if (a_is_zero | b_is_zero) begin
            // 0 × anything → signed zero
            special_result = result_sign ? 32'h80000000 : 32'h00000000;
        end
        else begin
            special_result = 32'h00000000;
        end
    end

endmodule
